# OEIS sequence: A100778

from itertools import count
from sympy import prime, integer_nthroot
from oeis_sequences.OEISsequences import bisection
def A100778(n):
    def g(x):
        c = 1
        for i in count(1):
            c *= prime(i)
            if c>x:
                return i-1
    def f(x): return n-1+x-sum(g(integer_nthroot(x,k)[0]) for k in range(1,x.bit_length()))
    return bisection(f,n,n) # _Chai Wah Wu_, Mar 28 2026

